label("3 cm",(0,4.5),W);
label("9 cm",(13.5,0),S);
draw(rightanglemark((0,9),(0,0),(27,0),35));
draw(rightanglemark((0,0),(0,9),(15,9),35));
draw(rightanglemark((15,9),(15,0),(27,0),35));
draw((15,0)--(15,9),linetype("2 4"));
[/asy]

